import { readFile } from "node:fs/promises";
import { resolve } from "node:path";
import { runCodex } from "../agent";
import { getThreadId, saveThreadId } from "../db";

export const AGENT_NAMES = ["strategist", "research", "execution", "coder"] as const;
export type AgentName = (typeof AGENT_NAMES)[number];

export interface PersonaResult {
  text: string;
  threadId: string | null;
}

export async function runPersona(
  chatId: string,
  agentName: AgentName,
  instruction: string
): Promise<PersonaResult> {
  const personaPath = resolve(process.cwd(), "personas", `${agentName}.md`);

  let persona: string;
  try {
    persona = await readFile(personaPath, "utf8");
  } catch (e: any) {
    throw new Error(`Missing persona file for "${agentName}": ${personaPath}`);
  }

  const previousThreadId = getThreadId(chatId, agentName) ?? undefined;

  const prompt = [
    persona.trim(),
    "",
    "Task:",
    instruction.trim(),
    "",
    "Output requirements:",
    "- Follow all persona constraints exactly.",
    "- Keep output concise and actionable."
  ].join("\n");

  const result = await runCodex(prompt, previousThreadId);

  const threadId = result.threadId ?? previousThreadId ?? null;
  if (threadId) saveThreadId(chatId, agentName, threadId);

  return { text: result.text, threadId };
}

