import { Context, Telegraf } from "telegraf";
import { runPersona } from "./agents/runner";
import { config } from "./config";
import { resetChatThreads } from "./db";
import { logger } from "./logger";

type AppBot = Telegraf<Context>;

function getChatId(ctx: Context): string | null {
  const chatId = ctx.chat?.id;
  return typeof chatId === "number" ? String(chatId) : null;
}

function readCommandArgument(ctx: Context, command: string): string {
  const message = ctx.message;
  if (!message || !("text" in message)) {
    return "";
  }

  const regex = new RegExp(`^/${command}(?:@\\w+)?\\s*`, "i");
  return message.text.replace(regex, "").trim();
}

async function withTyping(ctx: Context, action: () => Promise<void>): Promise<void> {
  const sendTyping = async () => {
    try {
      await ctx.sendChatAction("typing");
    } catch {
      // Ignore chat action errors to avoid blocking command execution.
    }
  };

  await sendTyping();
  const timer = setInterval(() => {
    void sendTyping();
  }, 4000);

  try {
    await action();
  } finally {
    clearInterval(timer);
  }
}

function attachCommands(bot: AppBot): void {
  bot.start(async (ctx) => {
    await ctx.reply([
      "CodexClaw Pro is online.",
      "/plan [optional focus]",
      "/monitor [optional scope]",
      "/build [development task]",
      "/reset"
    ].join("\n"));
  });

  bot.command("plan", async (ctx) => {
    const chatId = getChatId(ctx);
    if (!chatId) {
      return;
    }

    await withTyping(ctx, async () => {
      const focus = readCommandArgument(ctx, "plan");
      const researchPrompt = focus
        ? `Run a focused market scan for: ${focus}. Cover momentum, mean reversion, breakout, and volatility setups with structured trade ideas.`
        : "Run a daily market scan. Cover momentum, mean reversion, breakout, and volatility setups with structured trade ideas.";

      const research = await runPersona(chatId, "research", researchPrompt);

      const strategistPrompt = [
        "Create today's trading plan using the research below.",
        "Include priority setups, risk budget guidance, and a monitoring checklist.",
        "",
        "Research briefing:",
        research.text
      ].join("\n");

      const strategist = await runPersona(chatId, "strategist", strategistPrompt);
      await ctx.reply(strategist.text);
    });
  });

  bot.command("monitor", async (ctx) => {
    const chatId = getChatId(ctx);
    if (!chatId) {
      return;
    }

    await withTyping(ctx, async () => {
      const scope = readCommandArgument(ctx, "monitor");
      const prompt = scope
        ? `Monitor current positions with this scope: ${scope}. Recommend hold, stop adjustment, or close actions only.`
        : "Monitor current positions. Recommend hold, stop adjustment, or close actions only.";

      const execution = await runPersona(chatId, "execution", prompt);
      await ctx.reply(execution.text);
    });
  });

  bot.command("build", async (ctx) => {
    const chatId = getChatId(ctx);
    if (!chatId) {
      return;
    }

    await withTyping(ctx, async () => {
      const task = readCommandArgument(ctx, "build");
      const prompt = task.length > 0
        ? `Complete this platform development task: ${task}`
        : "Propose and detail the next platform development task for CodexClaw Pro.";

      const coder = await runPersona(chatId, "coder", prompt);
      await ctx.reply(coder.text);
    });
  });

  bot.command("reset", async (ctx) => {
    const chatId = getChatId(ctx);
    if (!chatId) {
      return;
    }

    const removed = resetChatThreads(chatId);
    await ctx.reply(`Reset complete. Cleared ${removed} saved thread session(s).`);
  });

  bot.catch(async (error, ctx) => {
    logger.error(
      {
        err: error,
        message: (error as any)?.message,
        stack: (error as any)?.stack,
        telegram: (error as any)?.response ?? (error as any)?.on?.payload,
      },
      "Telegram command error"
    );
    try {
      await ctx.reply("Request failed. Check logs and try again.");
    } catch {
      // Ignore downstream reply errors.
    }
  });
}

export function createBot(): AppBot | null {
  if (!config.telegramBotToken) {
    logger.warn("TELEGRAM_BOT_TOKEN is not set. Telegram bot is disabled.");
    return null;
  }

  const bot = new Telegraf<Context>(config.telegramBotToken);
  attachCommands(bot);
  return bot;
}
